import{_ as e,o as a,c as s,ag as r}from"./chunks/framework.6MCaaFDc.js";const h=JSON.parse('{"title":"DBMS Software","description":"","frontmatter":{},"headers":[],"relativePath":"theory/databases/dbms-software.md","filePath":"theory/databases/dbms-software.md"}'),i={name:"theory/databases/dbms-software.md"};function n(o,t,d,l,c,p){return a(),s("div",null,[...t[0]||(t[0]=[r(`<h1 id="dbms-software" tabindex="-1">DBMS Software <a class="header-anchor" href="#dbms-software" aria-label="Permalink to &quot;DBMS Software&quot;">​</a></h1><p>A database is only as useful as the software managing it. A Database Management System (DBMS) is the engine behind every application that stores structured data — from a school timetable to a bank&#39;s transaction records.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11</p><p>DBMS concepts, software types, and roles are Grade 11 content.</p></div><hr><h2 id="what-is-a-dbms" tabindex="-1">What is a DBMS? <a class="header-anchor" href="#what-is-a-dbms" aria-label="Permalink to &quot;What is a DBMS?&quot;">​</a></h2><p>A <strong>DBMS</strong> (Database Management System) is software that creates, manages, and controls access to a database.</p><p>The DBMS sits between the user/application and the raw data:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User / Application</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>     DBMS</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>   Database (stored data files)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>Functions of a DBMS:</strong></p><ul><li>Create and define database structure (tables, fields, keys)</li><li>Add, update, delete, and retrieve data</li><li>Enforce data integrity rules</li><li>Manage concurrent access (multiple users at once)</li><li>Control security and access permissions</li><li>Handle backup and recovery</li><li>Provide query language (SQL)</li></ul><hr><h2 id="types-of-dbms" tabindex="-1">Types of DBMS <a class="header-anchor" href="#types-of-dbms" aria-label="Permalink to &quot;Types of DBMS&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Relational DBMS (RDBMS)</strong></td><td>Data stored in related tables; uses SQL</td><td>MySQL, MS Access, PostgreSQL, Oracle</td></tr><tr><td><strong>NoSQL DBMS</strong></td><td>Non-tabular storage (documents, graphs, key-value)</td><td>MongoDB, Firebase, Redis</td></tr><tr><td><strong>Hierarchical DBMS</strong></td><td>Data in tree structure (parent-child)</td><td>IBM IMS — legacy mainframes</td></tr><tr><td><strong>Network DBMS</strong></td><td>Data in graph structure</td><td>Legacy — rarely used</td></tr><tr><td><strong>Object-oriented DBMS</strong></td><td>Data as objects (with methods)</td><td>db4o — mostly research</td></tr></tbody></table><p>The <strong>RDBMS</strong> is by far the most common and is the focus of the CAPS IT curriculum.</p><hr><h2 id="common-rdbms-software" tabindex="-1">Common RDBMS Software <a class="header-anchor" href="#common-rdbms-software" aria-label="Permalink to &quot;Common RDBMS Software&quot;">​</a></h2><h3 id="microsoft-access" tabindex="-1">Microsoft Access <a class="header-anchor" href="#microsoft-access" aria-label="Permalink to &quot;Microsoft Access&quot;">​</a></h3><ul><li>Desktop RDBMS included in Microsoft Office</li><li>Designed for small to medium databases</li><li>Graphical interface — no coding required for basic use</li><li>Supports SQL queries, forms, reports</li><li>File format: <code>.accdb</code></li><li><strong>Used in</strong>: school computer labs, small business record-keeping</li><li><strong>Limitations</strong>: single-user (or small multi-user via network share), max 2 GB database size</li></ul><h3 id="mysql" tabindex="-1">MySQL <a class="header-anchor" href="#mysql" aria-label="Permalink to &quot;MySQL&quot;">​</a></h3><ul><li>Open-source, free RDBMS</li><li>Server-based — handles thousands of concurrent users</li><li>Used by most websites and web applications</li><li>Command-line interface + many GUI tools (MySQL Workbench)</li><li><strong>Used in</strong>: web development (WordPress, Facebook originally), e-commerce</li><li><strong>Managed by</strong>: Oracle Corporation</li></ul><h3 id="postgresql" tabindex="-1">PostgreSQL <a class="header-anchor" href="#postgresql" aria-label="Permalink to &quot;PostgreSQL&quot;">​</a></h3><ul><li>Open-source, feature-rich RDBMS</li><li>More advanced than MySQL — better for complex queries</li><li>Excellent standards compliance</li><li>Used in enterprise and data-intensive applications</li><li><strong>Used in</strong>: scientific applications, GIS, enterprise systems</li></ul><h3 id="microsoft-sql-server" tabindex="-1">Microsoft SQL Server <a class="header-anchor" href="#microsoft-sql-server" aria-label="Permalink to &quot;Microsoft SQL Server&quot;">​</a></h3><ul><li>Enterprise RDBMS by Microsoft</li><li>Powerful — high performance and security features</li><li>Integrates tightly with Microsoft technologies</li><li>Expensive — used in large corporations</li><li><strong>Used in</strong>: banking, enterprise applications, Microsoft ecosystems</li></ul><h3 id="oracle-database" tabindex="-1">Oracle Database <a class="header-anchor" href="#oracle-database" aria-label="Permalink to &quot;Oracle Database&quot;">​</a></h3><ul><li>Industry-leading enterprise RDBMS</li><li>Most feature-rich and powerful commercial option</li><li>Very expensive — used by large corporations and governments</li><li><strong>Used in</strong>: major banks, airlines, government systems</li></ul><h3 id="sqlite" tabindex="-1">SQLite <a class="header-anchor" href="#sqlite" aria-label="Permalink to &quot;SQLite&quot;">​</a></h3><ul><li>Lightweight, file-based RDBMS</li><li>No separate server process — runs inside the application</li><li>Entire database stored in a single <code>.db</code> file</li><li><strong>Used in</strong>: mobile apps (iOS, Android), browsers, small applications, testing</li></ul><hr><h2 id="dbms-comparison" tabindex="-1">DBMS Comparison <a class="header-anchor" href="#dbms-comparison" aria-label="Permalink to &quot;DBMS Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>MS Access</th><th>MySQL</th><th>PostgreSQL</th><th>SQL Server</th><th>SQLite</th></tr></thead><tbody><tr><td>Cost</td><td>Paid (Office)</td><td>Free</td><td>Free</td><td>Expensive</td><td>Free</td></tr><tr><td>Users</td><td>Single/small</td><td>Thousands</td><td>Thousands</td><td>Thousands</td><td>Single</td></tr><tr><td>Interface</td><td>GUI</td><td>CLI + GUI</td><td>CLI + GUI</td><td>GUI + CLI</td><td>CLI + GUI</td></tr><tr><td>Scale</td><td>Small</td><td>Medium-large</td><td>Large</td><td>Enterprise</td><td>Small/embedded</td></tr><tr><td>SQL support</td><td>Partial</td><td>Full</td><td>Full</td><td>Full</td><td>Most</td></tr><tr><td>Use case</td><td>School/small biz</td><td>Web apps</td><td>Enterprise</td><td>Corporate</td><td>Mobile/embedded</td></tr></tbody></table><hr><h2 id="roles-in-database-management" tabindex="-1">Roles in Database Management <a class="header-anchor" href="#roles-in-database-management" aria-label="Permalink to &quot;Roles in Database Management&quot;">​</a></h2><h3 id="database-administrator-dba" tabindex="-1">Database Administrator (DBA) <a class="header-anchor" href="#database-administrator-dba" aria-label="Permalink to &quot;Database Administrator (DBA)&quot;">​</a></h3><p>The <strong>DBA</strong> is responsible for the overall management of the database system.</p><p><strong>Responsibilities:</strong></p><ul><li>Installing and configuring DBMS software</li><li>Designing database structure</li><li>Creating user accounts and assigning permissions</li><li>Monitoring performance and optimising queries</li><li>Scheduling and managing backups</li><li>Ensuring security and data integrity</li><li>Applying patches and upgrades</li><li>Disaster recovery planning</li></ul><h3 id="database-developer-programmer" tabindex="-1">Database Developer / Programmer <a class="header-anchor" href="#database-developer-programmer" aria-label="Permalink to &quot;Database Developer / Programmer&quot;">​</a></h3><p>Writes SQL queries, stored procedures, and integrates databases into applications.</p><p><strong>Responsibilities:</strong></p><ul><li>Writing complex SQL queries</li><li>Creating stored procedures and triggers</li><li>Connecting databases to application code (e.g. Delphi, PHP)</li><li>Optimising slow queries</li></ul><h3 id="database-analyst-bi-analyst" tabindex="-1">Database Analyst / BI Analyst <a class="header-anchor" href="#database-analyst-bi-analyst" aria-label="Permalink to &quot;Database Analyst / BI Analyst&quot;">​</a></h3><p>Analyses data to extract insights for business decision-making.</p><p><strong>Responsibilities:</strong></p><ul><li>Writing reporting queries</li><li>Creating dashboards and reports</li><li>Data cleaning and preparation</li><li>Identifying trends in data</li></ul><h3 id="end-user" tabindex="-1">End User <a class="header-anchor" href="#end-user" aria-label="Permalink to &quot;End User&quot;">​</a></h3><p>Uses the database through an application — usually without directly writing SQL.</p><hr><h2 id="query-processing" tabindex="-1">Query Processing <a class="header-anchor" href="#query-processing" aria-label="Permalink to &quot;Query Processing&quot;">​</a></h2><p>When a SQL query is submitted to a DBMS:</p><ol><li><strong>Parser</strong> — checks SQL syntax for errors</li><li><strong>Query optimiser</strong> — determines the most efficient execution plan</li><li><strong>Execution engine</strong> — retrieves data according to the plan</li><li><strong>Buffer manager</strong> — manages data in memory vs disk</li><li><strong>Result</strong> — returned to the application</li></ol><p><strong>Indexes:</strong></p><ul><li>An <strong>index</strong> speeds up data retrieval, similar to a book index</li><li>Created on frequently searched columns</li><li>Trade-off: indexes speed up reads but slow down writes (index must be updated when data changes)</li></ul><hr><h2 id="backup-and-recovery-in-dbms" tabindex="-1">Backup and Recovery in DBMS <a class="header-anchor" href="#backup-and-recovery-in-dbms" aria-label="Permalink to &quot;Backup and Recovery in DBMS&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><strong>Full database backup</strong></td><td>Complete copy of all data</td></tr><tr><td><strong>Transaction log backup</strong></td><td>Record of every change — allows point-in-time recovery</td></tr><tr><td><strong>Incremental backup</strong></td><td>Only changes since last backup</td></tr><tr><td><strong>Hot backup</strong></td><td>Backup while database is online (no downtime)</td></tr><tr><td><strong>Cold backup</strong></td><td>Backup while database is offline</td></tr></tbody></table><p><strong>Recovery scenarios:</strong></p><ul><li>Hardware failure → restore from backup</li><li>Corruption → restore + replay transaction logs</li><li>Accidental deletion → restore to point before deletion</li></ul><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>DBMS</strong></td><td>Software managing and controlling access to a database</td></tr><tr><td><strong>RDBMS</strong></td><td>Relational DBMS — data stored in related tables</td></tr><tr><td><strong>MS Access</strong></td><td>Desktop RDBMS for small databases</td></tr><tr><td><strong>MySQL</strong></td><td>Open-source server RDBMS for web applications</td></tr><tr><td><strong>PostgreSQL</strong></td><td>Open-source enterprise RDBMS</td></tr><tr><td><strong>DBA</strong></td><td>Database Administrator — manages the overall database system</td></tr><tr><td><strong>Index</strong></td><td>Data structure speeding up retrieval of specific values</td></tr><tr><td><strong>Query optimiser</strong></td><td>DBMS component that finds the most efficient execution plan</td></tr><tr><td><strong>Stored procedure</strong></td><td>Pre-compiled SQL stored in the database for reuse</td></tr><tr><td><strong>Concurrent access</strong></td><td>Multiple users reading/writing simultaneously</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is a DBMS? Give TWO examples.&quot;</strong> — Software that manages and controls access to a database; examples: Microsoft Access, MySQL, PostgreSQL, SQL Server</p></li><li><p><strong>&quot;Give THREE functions of a DBMS&quot;</strong> — Define database structure; retrieve/add/update/delete data; enforce data integrity; manage security and access; backup and recovery; handle concurrent access</p></li><li><p><strong>&quot;What are the responsibilities of a DBA?&quot;</strong> — Installing/configuring DBMS; designing structure; creating users and permissions; backup and recovery; monitoring performance; ensuring security</p></li><li><p><strong>&quot;Give ONE advantage and ONE disadvantage of Microsoft Access compared to MySQL&quot;</strong> — Advantage: graphical interface, no setup required, suitable for beginners; Disadvantage: limited to small databases, poor multi-user support, max 2 GB</p></li><li><p><strong>&quot;What is an index in a database? What is the trade-off?&quot;</strong> — Speeds up data retrieval on searched columns; trade-off: slows down write operations as the index must be updated with every data change</p></li></ol></div>`,64)])])}const g=e(i,[["render",n]]);export{h as __pageData,g as default};
